import type { Point2D } from '@kyokuya/particle-helper'
import {
  CanvasParticle2D as ParticleEffect2D,
  random,
  range,
} from '@kyokuya/particle-helper'

type CSSColor = Exclude<React.CSSProperties['color'], undefined>

interface Point extends Point2D {
  /**
   * Point color.
   */
  color: CSSColor
}

export interface ParticleEffectNestProps {
  /**
   * The number of points.
   * @default 99
   */
  numOfPoints?: number
  /**
   * The radius of the point.
   * @default 1
   */
  pointRadius?: number
  /**
   * The square of the maximum straight-line distance between two points that
   * can be connected.
   * @default 77
   */
  lineMaxDistance?: number
  /**
   * The color of the point.
   * @default () => '#000'
   */
  pointColor?(): CSSColor
  /**
   * The color of the stroke line.
   * @default () => 'rgba(0,0,0,0.9)'
   */
  lineColor?(): CSSColor
}

export class ParticleEffectNest extends ParticleEffect2D {
  protected readonly points: Point[]
  protected readonly numOfPoints: number
  protected readonly pointRadius: number
  protected readonly lineMaxDistance: number
  protected readonly lineColor: () => CSSColor
  protected readonly pointColor: () => CSSColor
  protected current: Point | null

  constructor(container: HTMLElement, options: ParticleEffectNestProps = {}) {
    super(container)
    this.numOfPoints = options.numOfPoints ?? 99
    this.pointRadius = options.pointRadius ?? 1
    this.lineMaxDistance = options.lineMaxDistance ?? 77
    this.pointColor = options.pointColor ?? (() => '#333')
    this.lineColor = options.lineColor ?? (() => '#111')
    this.points = this.createRandomPoints(this.numOfPoints)
    this.current = null
  }

  /**
   * Start animation.
   */
  public override start(): void {
    super.start()
    this.container.addEventListener('mousemove', this.onmousemove)
    this.container.addEventListener('mouseout', this.onmouseout)
  }

  /**
   * Perform clean operations.
   */
  public override destroy(): void {
    super.destroy()
    this.container.removeEventListener('mousemove', this.onmousemove)
    this.container.removeEventListener('mouseout', this.onmouseout)
  }

  /**
   * Render the contents of the current frame on the canvas.
   */
  protected override draw(): void {
    const {
      canvas,
      context,
      current,
      points,
      pointRadius,
      lineMaxDistance,
      lineColor,
    } = this

    const negativeLineMaxDistance = -lineMaxDistance
    const lineMaxDistanceSquared = lineMaxDistance * lineMaxDistance
    const { width, height } = canvas
    const pointDiameter = pointRadius * 2

    // Clear the entire canvas.
    context.clearRect(0, 0, width, height)

    /**
     * Draw a line between point p and point q.
     * @param p
     * @param q
     */
    const drawLine = (p: Point, q: Point): void => {
      const dx = p.x - q.x
      if (dx > lineMaxDistance || dx < negativeLineMaxDistance) return

      const dy = p.y - q.y
      if (dy > lineMaxDistance || dy < negativeLineMaxDistance) return

      const distance = dx * dx + dy * dy
      if (distance > lineMaxDistanceSquared) return

      const ratio = (lineMaxDistanceSquared - distance) / lineMaxDistanceSquared
      context.beginPath()
      context.lineWidth = ratio / 2
      context.strokeStyle = lineColor()
      context.moveTo(p.x, p.y)
      context.lineTo(q.x, q.y)
      context.stroke()
    }

    for (let i = 0; i < points.length; ++i) {
      const x = points[i]

      // Move point.
      x.x += x.vx
      x.y += x.vy

      // Collision detection.
      if (x.x < 0 || x.x > width) x.vx = -x.vx
      if (x.y < 0 || x.y > height) x.vy = -x.vy

      // Draw a point.
      context.fillStyle = x.color
      context.fillRect(
        x.x - pointRadius,
        x.y - pointRadius,
        pointDiameter,
        pointDiameter,
      )

      // Draw lines with other points.
      for (let j = i + 1; j < points.length; ++j) {
        const y = points[j]
        drawLine(x, y)
      }

      // Try to connect to the current point.
      if (current != null) {
        const dx = x.x - current.x
        const dy = x.y - current.y
        const distance = dx * dx + dy * dy
        if (distance <= lineMaxDistanceSquared) {
          if (distance * 2 >= lineMaxDistanceSquared) {
            x.x -= 0.02 * dx
            x.y -= 0.02 * dy
          }
          drawLine(x, current)
        }
      }
    }
  }

  /**
   * Create random nest points.
   * @param n
   * @returns
   */
  protected createRandomPoints = (n: number): Point[] => {
    const { canvas, pointColor } = this
    const { width, height } = canvas
    return range(n).map(
      (): Point => ({
        x: Math.random() * width,
        y: Math.random() * height,
        vx: random(-0.5, 0.5),
        vy: random(-0.5, 0.5),
        color: pointColor(),
      }),
    )
  }

  // on mouse move
  protected onmousemove = (e: MouseEvent): void => {
    const { clientX, clientY } = e
    const { offsetLeft, offsetTop } = this.container
    const { scrollLeft, scrollTop } = document.scrollingElement!

    this.current = {
      x: clientX - offsetLeft + scrollLeft,
      y: clientY - offsetTop + scrollTop,
      vx: 0,
      vy: 0,
      color: '',
    }
  }

  // on mouse out
  protected onmouseout = (): void => {
    this.current = null
  }
}

export default ParticleEffectNest
